LAYER
	NAME "lote"
	TYPE polygon
	STATUS on
	DATA "geom FROM (SELECT gid, id_ubigeo, cod_sector, cod_mzna, cod_lote, id_lote, ROUND(area_grafi::numeric, 2) AS area_grafi, ROUND(peri_grafi::numeric, 2) AS peri_grafi, cuc, geom FROM geo.tg_lote) as kaypacha using unique gid using srid=32719"
	INCLUDE "configuracion/postgresql_allpa.map"
	CLASSITEM "gid"
	PROJECTION
	"init=epsg:32719"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"
		"wfs_abstract" "Lote || Municipalidad Provincial de Espinar - Cusco :: Perú"
		"wfs_title" "Lote"
		"wfs_credit" "MPE"
		"wfs_srs" "EPSG:32719"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		#"gml_nume_doc_type" "Character"
		"gml_idlote_type" "Character"
		"wfs_getfeature_formatlist" "OGRGML,SHAPE-ZIP,CSV,geojson"
		#"wfs_additional_files_in_output" "lotes.pdf,lotes.lyr"
	END
	CLASS
		NAME "Lote"
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 100 107 99
			WIDTH 1
		END
	END
END # Layer